#!/bin/bash
# HealthLens 一键部署脚本
# 用法: bash deploy_healthlens.sh

set -e
echo "🧬 HealthLens 部署开始..."

# 1. 创建目录并解压文件
mkdir -p /home/ubuntu/healthlens
cd /home/ubuntu/healthlens

echo "📦 解压文件..."
echo "" | base64 -d | tar xzf -

# 2. 创建必要目录
mkdir -p uploads data

# 3. Docker构建部署
echo "🐳 Docker构建中..."
docker-compose down 2>/dev/null || true
docker-compose up -d --build 2>&1

# 4. 等待启动
echo "⏳ 等待服务启动..."
sleep 8

# 5. 健康检查
echo "🔍 健康检查..."
HEALTH=$(curl -s http://localhost:8432/health 2>/dev/null || echo "failed")
echo "$HEALTH"

if echo "$HEALTH" | grep -q "healthy"; then
    echo ""
    echo "✅ HealthLens 部署成功！"
    echo "   访问: http://150.158.119.19:8432"
else
    echo ""
    echo "⚠️ 健康检查未通过，查看日志:"
    docker-compose logs --tail 20
fi
